module RefModule(datain, dataout, load, initialize, clock);
input [4:0] datain;
input load, initialize;
input clock;
output [4:0] dataout;
reg [4:0] out;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or posedge dbg_halt)
begin
    if(initialize)
       out <= 5'b10000;
    else if(load)
       out <= datain;
    else
       out <= 5'b0;
end
assign dataout = out;
endmodule
